const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

const events = [
  {
    summary: "🌅 Подъём",
    start: "05:00:00",
    end: "05:15:00",
    description: "Проснуться, немного потянуться и обдумать планы на день в тишине."
  },
  {
    summary: "📱 Информационный менеджмент",
    start: "05:15:00",
    end: "05:30:00",
    description: "Взять телефон, проверить все пришедшие за ночь сообщения, напоминания и внешние рабочие вопросы/уведомления."
  },
  {
    summary: "❤️ Написать Олене",
    start: "05:30:00",
    end: "05:35:00",
    description: "Напоминание: Открыть Telegram-канал и написать Олене «Доброго ранку»."
  },
  {
    summary: "🎵 Настройка на день",
    start: "05:35:00",
    end: "05:45:00",
    description: "Посмотреть в окно, поприветствовать новое утро (громко вслух!), включить трек Дана Балана для хорошего настроения."
  },
  {
    summary: "📚 Образовательный блок (Языки)",
    start: "05:45:00",
    end: "07:30:00",
    description: "Изучение иностранных языков: Duolingo: Базовый курс + дополнительный курс; Промова: Практика языков (Албанский и Английский)."
  },
  {
    summary: "🌊 Спорт и море",
    start: "07:30:00",
    end: "09:00:00",
    description: "Пойти пешком на море, купание и утренний пляж (купи-купи)."
  },
  {
    summary: "🍳 Домашний блок",
    start: "09:00:00",
    end: "10:00:00",
    description: "Возвращение домой, душ, чистка зубов, приготовление и прием здорового завтрака, небольшой отдых."
  },
  {
    summary: "💻 Старт рабочего дня",
    start: "10:00:00",
    end: "10:30:00",
    description: "Создание и публикация постов в социальных сетях."
  }
];

// We will format the start and end dates as ISO-like strings with local offset (using the n8n execution timezone)
return events.map(event => {
  return {
    json: {
      summary: event.summary,
      description: event.description,
      // Let's output time in local format for Google Calendar node
      startTime: `${today}T${event.start}`,
      endTime: `${today}T${event.end}`
    }
  };
});
